/**
 * Config Loader — HelloCash Business → Odoo accounting sync.
 * Validates env; returns config for $('Config Loader').first().json.
 * ODOO_PASSWORD is required here but never included in output json.
 */

const REQUIRED = [
  'HELLOCASH_BASE_URL',
  'ODOO_BASE_URL',
  'ODOO_DB',
  'ODOO_UID',
  'ODOO_PASSWORD',
  'ODOO_JOURNAL_ID',
  'ACCOUNT_KASSE',
  'ACCOUNT_BANK',
  'ACCOUNT_ERLOESE',
  'ACCOUNT_GUTSCHEIN',
  'TAX_ID_19',
  'TAX_ID_7',
  'SYNC_HOUR',
  'ERROR_EMAIL',
];

for (const name of REQUIRED) {
  const val = $env[name];
  if (val === undefined || val === null || String(val).trim() === '') {
    throw new Error(
      `Config Loader: required environment variable is missing or empty: ${name}. ` +
        'Set it in n8n (Settings → Variables / environment) and ensure this execution can read it.',
    );
  }
}

/** @param {string} envName @param {string | number} raw */
function parseIntEnv(envName, raw) {
  const n = parseInt(String(raw).trim(), 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Config Loader: ${envName} must be a finite integer, got: ${JSON.stringify(raw)}`);
  }
  return n;
}

const kasse = parseIntEnv('ACCOUNT_KASSE', $env.ACCOUNT_KASSE);
const bank = parseIntEnv('ACCOUNT_BANK', $env.ACCOUNT_BANK);
const erloese = parseIntEnv('ACCOUNT_ERLOESE', $env.ACCOUNT_ERLOESE);
const gutschein = parseIntEnv('ACCOUNT_GUTSCHEIN', $env.ACCOUNT_GUTSCHEIN);
/** Odoo tax record for 19% USt (standard); not the Austrian 20% MwSt record. */
const taxId19 = parseIntEnv('TAX_ID_19', $env.TAX_ID_19);
const taxId7 = parseIntEnv('TAX_ID_7', $env.TAX_ID_7);

/** @type {Record<string, unknown>} */
const config = {
  /** HelloCash Business API base URL and HTTP timeout (NFR-3). */
  hellocash: {
    baseUrl: String($env.HELLOCASH_BASE_URL).trim().replace(/\/+$/, ''),
    timeoutMs: 30000,
  },

  /** Odoo JSON-RPC target (password stays in $env.ODOO_PASSWORD only). */
  odoo: {
    baseUrl: String($env.ODOO_BASE_URL).trim().replace(/\/+$/, ''),
    db: String($env.ODOO_DB).trim(),
    uid: parseIntEnv('ODOO_UID', $env.ODOO_UID),
    journalId: parseIntEnv('ODOO_JOURNAL_ID', $env.ODOO_JOURNAL_ID),
  },

  /** Payment bucket → { debit, credit } for Kasse/Bank/Gutschein → Erlöse. */
  accountMap: {
    CASH: { debit: kasse, credit: erloese },
    EC: { debit: bank, credit: erloese },
    CREDITCARD: { debit: bank, credit: erloese },
    VOUCHER: { debit: gutschein, credit: erloese },
  },

  /** VAT % → Odoo tax id on revenue line: 7% and 19% only (TAX_ID_7, TAX_ID_19). */
  taxMap: {
    7: taxId7,
    19: taxId19,
  },

  /** Retry policy for HTTP / RPC (NFR-3). */
  retry: {
    maxAttempts: 3,
    intervalMs: 5000,
  },

  syncHour: parseIntEnv('SYNC_HOUR', $env.SYNC_HOUR),

  errorEmail: String($env.ERROR_EMAIL).trim(),
};

return [{ json: config }];

/**
 * HelloCash Business — two-phase fetch (production).
 * Phase 1: GET /api/v1/cashBook (paginated limit/offset).
 * Phase 2: GET /api/v1/invoices per linked invoice number (payment + taxes).
 *
 * Env: HELLOCASH_API_TOKEN (required), HELLOCASH_LIST_PATH (default /api/v1/cashBook),
 * HELLOCASH_INVOICES_PATH (default /api/v1/invoices), HELLOCASH_DAYS_BACK (metadata only).
 * HELLOCASH_BASE_URL may be origin-only or include /api/v1 — overlapping path segments are merged (no /api/v1/api/v1/...).
 * HELLOCASH_QUERY_FROM / HELLOCASH_QUERY_TO → cashbook/invoices query dateFrom & dateTo (Apiary style).
 * Cashbook/invoices use: limit, offset, search, dateFrom, dateTo, mode, showDetails (mock-aligned).
 * Optional: HELLOCASH_IGNORE_SYNC_HOUR=1, SYNC_HOUR gate via Config.
 *
 * Note: n8n Code sandbox may not define URLSearchParams — use encodeURIComponent helper below.
 */

/**
 * Only include query keys that are actually set (not null/undefined; strings non-empty after trim).
 * @param {unknown} v
 */
function queryParamHasValue(v) {
  if (v === null || v === undefined) return false;
  if (typeof v === 'string') return v.trim() !== '';
  return true;
}

/** @param {Record<string, string | number | boolean>} params */
function buildQueryString(params) {
  return Object.keys(params)
    .filter((k) => queryParamHasValue(params[k]))
    .map((k) => `${encodeURIComponent(k)}=${encodeURIComponent(String(params[k]))}`)
    .join('&');
}

/**
 * Merge HELLOCASH_BASE_URL with an absolute path without duplicating shared segments.
 * e.g. base https://host/api/v1 + path /api/v1/cashBook → https://host/api/v1/cashBook
 * Protocol-relative bases (//host/...) are normalized to https://host/...
 *
 * @param {string} baseUrlRaw
 * @param {string} pathRaw absolute path, e.g. /api/v1/cashBook
 */
function joinBaseUrlAndPath(baseUrlRaw, pathRaw) {
  let baseStr = String(baseUrlRaw || '').trim();
  if (baseStr.startsWith('//')) baseStr = `https:${baseStr}`;
  baseStr = baseStr.replace(/\/+$/, '');

  const relPath = pathRaw.startsWith('/') ? pathRaw : `/${pathRaw}`;

  try {
    const u = new URL(baseStr);
    const rawBasePath = u.pathname || '/';
    const basePath = rawBasePath.replace(/\/+$/, '') || '';
    const baseSegs = basePath.split('/').filter(Boolean);
    const pathSegs = relPath.split('/').filter(Boolean);

    let overlap = 0;
    const max = Math.min(baseSegs.length, pathSegs.length);
    for (let k = max; k >= 1; k--) {
      let ok = true;
      for (let i = 0; i < k; i++) {
        if (baseSegs[baseSegs.length - k + i] !== pathSegs[i]) {
          ok = false;
          break;
        }
      }
      if (ok) {
        overlap = k;
        break;
      }
    }

    const remainder = pathSegs.slice(overlap);
    const mergedSegs = [...baseSegs, ...remainder];
    u.pathname = `/${mergedSegs.join('/')}`;
    return u.toString().replace(/\/+$/, '');
  } catch {
    return `${baseStr}${relPath}`;
  }
}

/**
 * n8n httpRequest: omit null/undefined options (some versions reject explicit nulls).
 * @param {Record<string, unknown>} opts
 */
function httpRequestOpts(opts) {
  /** @type {Record<string, unknown>} */
  const out = {};
  for (const [k, v] of Object.entries(opts)) {
    if (v !== null && v !== undefined) out[k] = v;
  }
  return out;
}

/**
 * Drop null/undefined and empty strings from nested objects for logs (avoid "parameters" with no value).
 * @param {unknown} value
 */
function compactForDisplay(value) {
  if (value === null || value === undefined) return undefined;
  if (Array.isArray(value)) {
    const arr = value.map(compactForDisplay).filter((x) => x !== undefined);
    return arr.length ? arr : undefined;
  }
  if (typeof value === 'object') {
    const o = {};
    for (const [k, v] of Object.entries(value)) {
      const c = compactForDisplay(v);
      if (c !== undefined) o[k] = c;
    }
    return Object.keys(o).length ? o : undefined;
  }
  if (typeof value === 'string' && value.trim() === '') return undefined;
  return value;
}

/**
 * One or two sentences an operator can act on (not only raw status/body).
 * @param {string|number} status
 * @param {{ name?: string, code?: string, httpCode?: string, message?: string, description?: string }} hint
 * @param {string} bodyStr
 */
function deriveFailureExplanation(status, hint, bodyStr) {
  const code = String(hint?.code ?? '');
  const msg = String(hint?.message ?? hint?.description ?? '');
  const statusNum = typeof status === 'number' ? status : parseInt(String(status), 10);
  const body = String(bodyStr ?? '');
  const combined = `${msg} ${code} ${body}`.toLowerCase();

  const parts = [];

  if (Number.isFinite(statusNum)) {
    if (statusNum === 401 || statusNum === 403) {
      parts.push(
        'The API rejected authentication/authorization — verify HELLOCASH_API_TOKEN and that HELLOCASH_BASE_URL matches the environment where that token is valid.',
      );
    } else if (statusNum === 404) {
      parts.push(
        'The server returned 404 — check HELLOCASH_BASE_URL and list/invoices paths (HELLOCASH_LIST_PATH, HELLOCASH_INVOICES_PATH).',
      );
    } else if (statusNum === 400 || statusNum === 422) {
      parts.push(
        'The server rejected the request parameters — review date/search/limit/offset env vars against the API contract.',
      );
    } else if (statusNum === 429) {
      parts.push('Rate limited (429) — retry later or reduce call volume.');
    } else if (statusNum >= 500 && statusNum < 600) {
      parts.push(
        `Server error (${statusNum}) — HelloCash may be unavailable; retry later or check their service status.`,
      );
    } else if (statusNum >= 200 && statusNum < 300) {
      parts.push(
        'HTTP status looks successful but the client still failed — the body may not be JSON while json:true is set, or the client threw for another reason.',
      );
    }
  }

  if (status === 'no-status' || !Number.isFinite(statusNum)) {
    if (/enotfound|getaddrinfo|eai_again/i.test(combined) || code === 'ENOTFOUND') {
      parts.push('DNS or hostname resolution failed — check HELLOCASH_BASE_URL and network/DNS.');
    }
    if (/econnrefused/i.test(combined) || code === 'ECONNREFUSED') {
      parts.push('Connection refused — wrong host/port, service not listening, or firewall.');
    }
    if (/etimedout|esockettimedout|timeout/i.test(combined) || /timeout/i.test(code)) {
      parts.push('Request timed out — increase HelloCash timeout in config, or check network/API availability.');
    }
    if (/cert|ssl|tls|unable_to_verify/i.test(combined)) {
      parts.push('TLS/certificate error — check HTTPS URL, proxy, or corporate TLS inspection.');
    }
  }

  if (/unexpected token|not valid json|invalid json|json parse/i.test(combined)) {
    parts.push('Response was not valid JSON — wrong URL often returns HTML or an error page instead of the API.');
  }
  if (/<!doctype html|<html/i.test(body)) {
    parts.push('Body looks like HTML — usually wrong API URL, redirect to a web login, or a gateway error page.');
  }

  if (parts.length === 0) {
    parts.push(
      'Could not infer a specific cause from status/body — use HTTP status, hint fields, and response snippet below.',
    );
  }

  return parts.join(' ');
}

/**
 * Best-effort HTTP status from n8n httpRequest / axios / nested cause chain.
 * @param {unknown} e
 */
function resolveHttpStatus(e) {
  /** @param {unknown} x */
  const asStatus = (x) => {
    if (x === undefined || x === null || x === '') return undefined;
    if (typeof x === 'number' && Number.isFinite(x)) return x;
    const n = parseInt(String(x), 10);
    if (Number.isFinite(n)) return n;
    if (typeof x === 'string') return x.trim() || undefined;
    return undefined;
  };

  let cur = e;
  for (let d = 0; d < 6 && cur != null; d++) {
    if (typeof cur !== 'object') break;
    const o = /** @type {Record<string, unknown>} */ (cur);
    const u =
      asStatus(o.response?.status) ??
      asStatus(o.response?.statusCode) ??
      asStatus(
        o.error && typeof o.error === 'object'
          ? /** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).status ??
              /** @type {{ status?: unknown, statusCode?: unknown }} */ (o.error).statusCode ??
              undefined
          : undefined,
      ) ??
      asStatus(o.httpCode) ??
      asStatus(o.statusCode) ??
      asStatus(o.status);
    if (u !== undefined) return u;
    cur = o.cause;
  }

  const msg = String(
    (typeof e === 'object' && e && 'message' in e && /** @type {{ message: unknown }} */ (e).message) || '',
  );
  const m =
    msg.match(/\bstatus code\s+(\d{3})\b/i) ??
    msg.match(/\bHTTP\s+(\d{3})\b/) ??
    msg.match(/^\s*(\d{3})\s/);
  if (m) return parseInt(m[1], 10);

  return 'no-status';
}

/**
 * n8n httpRequest errors are often NodeApiError / wrapped request errors — not always axios-shaped (e.response).
 */
function extractHttpFailureDetails(e) {
  const status = resolveHttpStatus(e);

  let body =
    e?.response?.data ??
    e?.response?.body ??
    e?.error ??
    e?.description ??
    (Array.isArray(e?.messages) ? e.messages.join('; ') : e?.messages);

  if ((body === undefined || body === null || body === '') && e?.cause) {
    const c = e.cause;
    body =
      c?.response?.data ??
      c?.response?.body ??
      c?.message ??
      (typeof c === 'string' ? c : undefined);
  }

  let bodyStr = 'no body';
  if (body !== undefined && body !== null && body !== '') {
    bodyStr = typeof body === 'string' ? body : JSON.stringify(body, null, 2);
  }

  const hint = {
    name: e?.name,
    code: e?.code,
    httpCode: e?.httpCode,
    description: e?.description,
    message: e?.message,
    stack: typeof e?.stack === 'string' ? e.stack : undefined,
    errorKeys: e && typeof e === 'object' ? Object.keys(e) : [],
  };

  /** @param {unknown} err @param {number} depth */
  function shallowDump(err, depth) {
    if (err == null) return null;
    if (typeof err !== 'object') return String(err);
    const o = {};
    try {
      for (const k of Object.getOwnPropertyNames(err)) {
        try {
          let v = /** @type {object} */ (err)[k];
          if (v && typeof v === 'object' && depth < 2) {
            v = shallowDump(v, depth + 1);
          }
          if (typeof v === 'string' && v.length > 4000) v = v.slice(0, 4000) + '…';
          o[k] = v;
        } catch {
          o[k] = '[unreadable]';
        }
      }
    } catch {
      return '[dump failed]';
    }
    return o;
  }

  const rawDump = shallowDump(e, 0);
  let causeChain = [];
  let c = e?.cause;
  let depth = 0;
  while (c != null && depth < 5) {
    causeChain.push({
      depth,
      message: c?.message ?? String(c),
      name: c?.name,
      stack: typeof c?.stack === 'string' ? c.stack.slice(0, 2000) : undefined,
    });
    c = c?.cause;
    depth++;
  }

  return { status, bodyStr, hint, rawDump, causeChain };
}

/** Mask secret for logs (never log full token). */
function maskToken(t) {
  const s = String(t || '');
  if (!s) return '(empty)';
  if (s.length <= 8) return `${s.slice(0, 2)}…(${s.length} chars)`;
  return `${s.slice(0, 4)}…${s.slice(-2)} (len=${s.length})`;
}

function safeJson(obj, space) {
  try {
    return JSON.stringify(obj, null, space);
  } catch {
    return '[JSON.stringify failed — possibly circular]';
  }
}

const config = $('Config Loader').first().json;
const token = $env.HELLOCASH_API_TOKEN?.trim();
if (!token) {
  throw new Error('HelloCash Fetch: HELLOCASH_API_TOKEN missing');
}

const ignoreHour =
  $env.HELLOCASH_IGNORE_SYNC_HOUR === '1' ||
  String($env.HELLOCASH_IGNORE_SYNC_HOUR || '').toLowerCase() === 'true';
const hour = new Date().getHours();
if (!ignoreHour && hour !== config.syncHour) {
  return [
    {
      json: {
        skipped: true,
        reason: 'sync_hour',
        syncHour: config.syncHour,
        currentHour: hour,
      },
    },
  ];
}

let baseUrl = String(config.hellocash.baseUrl || '')
  .trim()
  .replace(/\/+$/, '');
if (baseUrl.startsWith('//')) baseUrl = `https:${baseUrl}`;

const listPath = ($env.HELLOCASH_LIST_PATH && String($env.HELLOCASH_LIST_PATH).trim()) || '/api/v1/cashBook';
const invoicesPath =
  ($env.HELLOCASH_INVOICES_PATH && String($env.HELLOCASH_INVOICES_PATH).trim()) || '/api/v1/invoices';
const daysBack = parseInt(String($env.HELLOCASH_DAYS_BACK || '1'), 10);

const qFrom = ($env.HELLOCASH_QUERY_FROM && String($env.HELLOCASH_QUERY_FROM).trim()) || '';
const qTo = ($env.HELLOCASH_QUERY_TO && String($env.HELLOCASH_QUERY_TO).trim()) || '';

const cashbookOffset =
  $env.HELLOCASH_CASHBOOK_OFFSET !== undefined && $env.HELLOCASH_CASHBOOK_OFFSET !== null
    ? String($env.HELLOCASH_CASHBOOK_OFFSET)
    : '0';

const cashbookQuery = buildQueryString({
  limit: String($env.HELLOCASH_CASHBOOK_LIMIT || '1000'),
  offset: cashbookOffset,
  search: String($env.HELLOCASH_CASHBOOK_SEARCH || ''),
  dateFrom: qFrom,
  dateTo: qTo,
  mode: String($env.HELLOCASH_CASHBOOK_MODE || ''),
  showDetails: String($env.HELLOCASH_CASHBOOK_SHOW_DETAILS || ''),
});

const pathNorm = listPath.startsWith('/') ? listPath : `/${listPath}`;
const cashbookUrlNoQuery = joinBaseUrlAndPath(baseUrl, pathNorm);
const cashbookUrl = cashbookQuery ? `${cashbookUrlNoQuery}?${cashbookQuery}` : cashbookUrlNoQuery;

if (!String(baseUrl || '').trim()) {
  throw new Error(
    'HelloCash Fetch: config.hellocash.baseUrl is empty. Re-run Config Loader and set HELLOCASH_BASE_URL (non-empty).',
  );
}

const invPathNorm = invoicesPath.startsWith('/') ? invoicesPath : `/${invoicesPath}`;
const invoiceBaseUrl = joinBaseUrlAndPath(baseUrl, invPathNorm);

const { maxAttempts, intervalMs } = config.retry;
/** @type {Record<string, string>} */
const authHeaders = {
  Authorization: `Bearer ${token}`,
  Accept: 'application/json',
};

let lastErr;
/** @type {unknown} */
let cashbookResponse;
/** @type {object[]} */
const cashbookAttemptHistory = [];

for (let attempt = 1; attempt <= maxAttempts; attempt++) {
  const attemptStartedAt = new Date().toISOString();
  try {
    cashbookResponse = await this.helpers.httpRequest(
      httpRequestOpts({
        method: 'GET',
        url: cashbookUrl,
        headers: authHeaders,
        timeout: config.hellocash.timeoutMs,
        json: true,
      }),
    );
    lastErr = undefined;
    break;
  } catch (e) {
    const { status, bodyStr, hint, rawDump, causeChain } = extractHttpFailureDetails(e);
    const hintCompact = compactForDisplay(hint) ?? {};
    const failureExplanation = deriveFailureExplanation(status, hint, bodyStr);
    const reqUrl = cashbookUrl;

    const attemptRecord = {
      attempt,
      of: maxAttempts,
      at: attemptStartedAt,
      status,
      httpStatus: status,
      failureExplanation,
      url: reqUrl,
      urlParts: {
        baseUrl,
        pathNorm,
        joinedPath: cashbookUrlNoQuery,
        ...(cashbookQuery ? { query: cashbookQuery } : {}),
        fullUrlLength: String(reqUrl || '').length,
      },
      request: {
        method: 'GET',
        timeoutMs: config.hellocash.timeoutMs,
        accept: authHeaders.Accept,
        authorization: `Bearer ${maskToken(token)}`,
      },
      responseBody: bodyStr,
      responseBodyLength: String(bodyStr || '').length,
      hint: hintCompact,
      rawDump,
      causeChain,
    };
    cashbookAttemptHistory.push(attemptRecord);

    console.error('HelloCash cashbook fetch failed — attempt detail', attemptRecord);

    lastErr = new Error(
      `HTTP ${status} | HelloCash cashbook attempt ${attempt}/${maxAttempts} failed\n` +
        `Why: ${failureExplanation}\n` +
        `URL: ${reqUrl}\n` +
        `Response: ${bodyStr}\n` +
        `Hint: ${safeJson(hintCompact, 2)}\n` +
        `Cause chain: ${safeJson(causeChain, 2)}\n` +
        `Raw dump: ${safeJson(rawDump, 2)}`,
    );

    if (attempt < maxAttempts) {
      await new Promise((r) => setTimeout(r, intervalMs));
    }
  }
}
if (cashbookResponse === undefined) {
  const lastAtt =
    cashbookAttemptHistory.length > 0
      ? cashbookAttemptHistory[cashbookAttemptHistory.length - 1]
      : {};

  const bodyOneLine = String(lastAtt.responseBody ?? '')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 500);
  const hintMsg = lastAtt.hint?.message ?? lastAtt.hint?.description ?? 'n/a';
  const hintCode = lastAtt.hint?.code ?? lastAtt.hint?.httpCode ?? 'n/a';
  const failureExplanation =
    lastAtt.failureExplanation ??
    deriveFailureExplanation(lastAtt.status ?? 'no-status', lastAtt.hint ?? {}, bodyOneLine);

  const diagnostic = {
    phase: 'cashbook GET',
    httpStatus: lastAtt.status ?? 'no-status',
    nodeErrorCode: hintCode,
    failureExplanation,
    failedAfterAttempts: maxAttempts,
    retryIntervalMs: intervalMs,
    clock: { hour, syncHour: config.syncHour, ignoreSyncHour: ignoreHour },
    token: maskToken(token),
    cashbookUrl,
    invoiceBaseUrl,
    envPaths: {
      HELLOCASH_LIST_PATH: listPath,
      HELLOCASH_INVOICES_PATH: invoicesPath,
    },
    attemptHistory: cashbookAttemptHistory,
    lastErrorMessage: lastErr?.message ?? 'unknown',
    lastErrorStack: lastErr?.stack ?? 'no stack',
  };

  const diagnosticJson = safeJson(diagnostic, 2);

  console.error('HelloCash cashbook — FINAL FAILURE (all attempts exhausted)', {
    httpStatus: lastAtt.status ?? 'no-status',
    nodeErrorCode: hintCode,
    ...diagnostic,
  });

  const explainOneLine = String(failureExplanation).replace(/\s+/g, ' ').trim().slice(0, 280);

  const httpStatusStr =
    lastAtt.status !== undefined && lastAtt.status !== null && lastAtt.status !== 'no-status'
      ? `HTTP ${lastAtt.status}`
      : 'HTTP status unknown (no response — network/DNS/TLS/wrong URL?)';

  // n8n Error panel often shows only the FIRST line — lead with HTTP + node error code.
  const errorFirstLine =
    `${httpStatusStr} | nodeErrorCode=${hintCode} | HelloCash cashbook GET: ${maxAttempts} attempts failed | ${explainOneLine} | ${hintMsg} | URL=${cashbookUrl} | body=${bodyOneLine || '(empty)'}`;

  // One summary line already has URL + body; avoid repeating them via lastErr.message/stack here
  // (those are still in diagnostic.lastErrorMessage / lastErrorStack / attemptHistory for tools).
  const msg =
    `${errorFirstLine}\n` +
    `\n` +
    `--- CONTEXT ---\n` +
    `httpStatus: ${lastAtt.status ?? 'no-status'}  nodeErrorCode: ${hintCode}\n` +
    `invoiceBaseUrl: ${invoiceBaseUrl}\n` +
    `timeoutMs: ${config.hellocash.timeoutMs}  retryIntervalMs: ${intervalMs}\n` +
    `token (masked): ${maskToken(token)}\n` +
    `syncHour: ${config.syncHour}  currentHour: ${hour}  ignoreSyncHour: ${ignoreHour}\n` +
    `--- DIAGNOSTIC JSON ---\n` +
    diagnosticJson;

  const err = new Error(msg);
  err.diagnostic = diagnostic;
  err.attemptHistory = cashbookAttemptHistory;
  throw err;
}

const rawEntries =
  cashbookResponse && typeof cashbookResponse === 'object' && 'entries' in cashbookResponse
    ? cashbookResponse.entries
    : [];
const entries = Array.isArray(rawEntries) ? rawEntries : [];
if (entries.length === 0) {
  return [{ json: { skipped: false, empty: true, message: 'No cashbook entries' } }];
}

const invoiceNumbers = [
  ...new Set(
    entries
      .filter(
        (e) =>
          e &&
          typeof e === 'object' &&
          e.cashBook_invoice_number &&
          String(e.cashBook_invoice_number) !== '0' &&
          e.cashBook_cancellation !== '1',
      )
      .map((e) => String(/** @type {{ cashBook_invoice_number: string }} */ (e).cashBook_invoice_number)),
  ),
];

const invoicesMap = new Map();

for (const invNum of invoiceNumbers) {
  let invRequestUrl = invoiceBaseUrl;
  try {
    const invOffset =
      $env.HELLOCASH_INVOICES_OFFSET !== undefined && $env.HELLOCASH_INVOICES_OFFSET !== null
        ? String($env.HELLOCASH_INVOICES_OFFSET)
        : '0';
    const invDateFrom =
      $env.HELLOCASH_INVOICES_DATE_FROM !== undefined && $env.HELLOCASH_INVOICES_DATE_FROM !== null
        ? String($env.HELLOCASH_INVOICES_DATE_FROM)
        : qFrom;
    const invDateTo =
      $env.HELLOCASH_INVOICES_DATE_TO !== undefined && $env.HELLOCASH_INVOICES_DATE_TO !== null
        ? String($env.HELLOCASH_INVOICES_DATE_TO)
        : qTo;

    const invQuery = buildQueryString({
      limit: String($env.HELLOCASH_INVOICES_LIMIT || '1000'),
      offset: invOffset,
      search: invNum,
      dateFrom: invDateFrom,
      dateTo: invDateTo,
      mode: String($env.HELLOCASH_INVOICES_MODE || ''),
      showDetails: String($env.HELLOCASH_INVOICES_SHOW_DETAILS || ''),
    });

    invRequestUrl = invQuery ? `${invoiceBaseUrl}?${invQuery}` : `${invoiceBaseUrl}`;
    const invResponse = await this.helpers.httpRequest(
      httpRequestOpts({
        method: 'GET',
        url: invRequestUrl,
        headers: authHeaders,
        timeout: config.hellocash.timeoutMs,
        json: true,
      }),
    );
    const invList = invResponse?.invoices;
    if (Array.isArray(invList) && invList.length > 0) {
      const inv =
        invList.find((x) => x && String(x.invoice_number) === String(invNum)) ?? invList[0];
      if (inv && inv.invoice_cancellation !== '1') {
        invoicesMap.set(invNum, inv);
      }
    }
  } catch (e) {
    const { status, bodyStr, hint, rawDump, causeChain } = extractHttpFailureDetails(e);
    const failureExplanation = deriveFailureExplanation(status, hint, bodyStr);
    console.error('HelloCash invoice fetch failed', {
      invNum,
      attempt: 'single',
      httpStatus: status,
      failureExplanation,
      url: invRequestUrl,
      responseBody: bodyStr,
      hint: compactForDisplay(hint) ?? {},
      rawDump,
      causeChain,
    });
    const msg = e instanceof Error ? e.message : String(e);
    console.warn(`HelloCash Fetch: failed to fetch invoice ${invNum}: ${msg}`);
  }
}

return [
  {
    json: {
      skipped: false,
      hellocashData: {
        entries,
        invoices: Object.fromEntries(invoicesMap),
        meta: {
          fetchedAt: new Date().toISOString(),
          entryCount: entries.length,
          invoiceCount: invoicesMap.size,
          daysBack: Number.isFinite(daysBack) ? daysBack : 1,
        },
      },
    },
  },
];

/**
 * Map HelloCash cashbook entries (+ linked invoices) → Odoo account.move payloads.
 * Skips cancelled cashbook rows; tax on revenue (credit) line for deposits only.
 */

const config = $('Config Loader').first().json;
const input = items[0].json;

if (input.skipped || input.empty) {
  return [{ json: input }];
}

const hc = input.hellocashData;
if (!hc?.entries) {
  return [{ json: { skipped: false, mappedEmpty: true, message: 'Missing hellocashData.entries' } }];
}

const { entries, invoices } = hc;
/** @type {Record<string, unknown>} */
const invByNumber = invoices && typeof invoices === 'object' ? invoices : {};

if (entries.length === 0) {
  console.warn('Map to Odoo: HelloCash returned empty entries', {
    rawType: typeof hc,
    rawKeys: hc && typeof hc === 'object' ? Object.keys(hc) : [],
    fetchedAt: hc.meta?.fetchedAt ?? input.fetchedAt ?? 'unknown',
  });
  return [
    {
      json: {
        skipped: false,
        mappedEmpty: true,
        message: 'No rows to map from HelloCash payload',
      },
    },
  ];
}

console.log('HelloCash payload received', {
  entryCount: entries.length,
  firstEntry: entries[0] ?? null,
  fetchedAt: hc.meta?.fetchedAt ?? input.fetchedAt ?? 'unknown',
});

const out = [];

for (const entry of entries) {
  if (!entry || typeof entry !== 'object') continue;
  if (entry.cashBook_cancellation === '1') continue;

  const id = entry.cashBook_id;
  const number = entry.cashBook_number;
  const type = String(entry.cashBook_type || '').toLowerCase();
  const amount = Math.abs(parseFloat(String(entry.cashBook_total ?? '0')));
  if (!Number.isFinite(amount) || amount === 0) continue;

  const description = String(entry.cashBook_description || '');
  const invoiceNumber = entry.cashBook_invoice_number
    ? String(entry.cashBook_invoice_number)
    : '';

  const timestamp = String(entry.cashBook_timestamp || '');
  const date = timestamp.split(' ')[0] || new Date().toISOString().split('T')[0];

  const invoice = invoiceNumber && invByNumber[invoiceNumber] ? invByNumber[invoiceNumber] : null;

  let paymentMethod = 'CASH';
  if (invoice && typeof invoice === 'object' && invoice.invoice_payment) {
    const p = String(invoice.invoice_payment).toLowerCase();
    if (p.includes('ec') || p.includes('card') || p.includes('debit')) {
      paymentMethod = 'EC';
    } else if (p.includes('credit')) {
      paymentMethod = 'CREDITCARD';
    } else if (p.includes('voucher') || p.includes('gutschein') || p.includes('gut')) {
      paymentMethod = 'VOUCHER';
    } else if (p.includes('bar') || p.includes('cash')) {
      paymentMethod = 'CASH';
    }
  }

  let taxRate = 19;
  if (invoice && typeof invoice === 'object' && Array.isArray(invoice.taxes) && invoice.taxes.length > 0) {
    const tax = invoice.taxes[0];
    if (tax && typeof tax === 'object' && tax.tax_taxRate !== undefined) {
      taxRate = parseInt(String(tax.tax_taxRate), 10) || 19;
    }
  }

  const am = config.accountMap[paymentMethod];
  if (!am) {
    throw new Error(`Map: unknown payment method "${paymentMethod}" for entry ${id}`);
  }

  // Only 7% and 19% Odoo taxes (TAX_ID_7 / TAX_ID_19). HelloCash may send 20 (AT); map to 19% tax id.
  const taxLookupKey = taxRate === 20 ? 19 : taxRate;
  const taxId = config.taxMap[taxLookupKey] ?? config.taxMap[19];

  const isDeposit =
    type === 'deposit' || type === 'income' || type === 'sale' || type === 'einnahme';
  const isWithdrawal =
    type === 'withdrawal' ||
    type === 'payout' ||
    type === 'expense' ||
    type === 'refund' ||
    type === 'ausgabe';

  const ref = `HC-${number}-${id}`;

  let lineDebit;
  let lineCredit;

  if (isDeposit) {
    lineDebit = {
      account_id: am.debit,
      debit: amount,
      credit: 0,
      name: `HC ${number}: ${description.substring(0, 50)}`,
    };
    lineCredit = {
      account_id: am.credit,
      debit: 0,
      credit: amount,
      name: `HC ${number}: ${description.substring(0, 50)}`,
    };
    if (taxId) {
      lineCredit.tax_ids = [[6, 0, [taxId]]];
    }
  } else if (isWithdrawal) {
    lineDebit = {
      account_id: am.credit,
      debit: amount,
      credit: 0,
      name: `HC ${number} [${type}]: ${description.substring(0, 50)}`,
    };
    lineCredit = {
      account_id: am.debit,
      debit: 0,
      credit: amount,
      name: `HC ${number} [${type}]: ${description.substring(0, 50)}`,
    };
  } else {
    console.warn(`Map: unknown cashBook_type "${type}" for entry ${id}, skipping`);
    continue;
  }

  console.log(`Mapped entry ${id}`, {
    ref,
    paymentMethod,
    amount,
    taxRate,
    debitAccount: am.debit,
    creditAccount: am.credit,
  });

  out.push({
    json: {
      hellocashId: id,
      hellocashNumber: number,
      invoiceNumber: invoiceNumber || null,
      paymentMethod,
      taxRate,
      ref,
      odooVals: {
        ref,
        move_type: 'entry',
        journal_id: config.odoo.journalId,
        date,
        line_ids: [
          [0, 0, lineDebit],
          [0, 0, lineCredit],
        ],
        narration: `HelloCash Entry #${number} (ID:${id}), Type:${type}, Inv:${invoiceNumber || 'n/a'}, Pay:${paymentMethod}, Tax:${taxRate}%, Amt:${amount.toFixed(2)}`,
      },
    },
  });
}

if (out.length === 0) {
  return [
    {
      json: {
        skipped: false,
        mappedEmpty: true,
        message: 'No entries mapped (all cancelled or unknown type)',
      },
    },
  ];
}

return out;

/**
 * Odoo JSON-RPC: account.move create with idempotency (ref) and retries.
 * Uses $env.ODOO_PASSWORD (validated at Config Loader, never stored in config json).
 */

const config = $('Config Loader').first().json;
const pwd = $env.ODOO_PASSWORD?.trim();
if (!pwd) {
  throw new Error('Odoo Post Moves: ODOO_PASSWORD missing for JSON-RPC');
}

const { maxAttempts, intervalMs } = config.retry;
const results = [];

const rpc = async (model, method, args, kwargs = {}) => {
  const url = `${config.odoo.baseUrl}/jsonrpc`;
  const body = {
    jsonrpc: '2.0',
    method: 'call',
    params: {
      service: 'object',
      method: 'execute_kw',
      args: [
        config.odoo.db,
        config.odoo.uid,
        String(pwd).trim(),
        model,
        method,
        args,
        kwargs,
      ],
    },
    id: Date.now(),
  };

  let res;
  try {
    res = await this.helpers.httpRequest({
      method: 'POST',
      url,
      body,
      json: true,
      timeout: 120000,
      headers: { 'Content-Type': 'application/json' },
    });
  } catch (e) {
    const status = e.response?.status ?? 'no-status';
    const respBody = e.response?.data ?? e.response?.body ?? 'no body';
    console.error('Odoo HTTP error', {
      model,
      method,
      status,
      responseBody: respBody,
      message: e.message,
    });
    throw new Error(
      `Odoo HTTP ${status} calling ${model}.${method}\n` +
        `Response: ${JSON.stringify(respBody, null, 2)}`,
    );
  }

  if (res.error) {
    console.error('Odoo RPC error', {
      model,
      method,
      code: res.error.code,
      message: res.error.data?.message ?? res.error.message,
      debug: res.error.data?.debug ?? 'none',
    });
    throw new Error(
      `Odoo RPC error calling ${model}.${method}\n` +
        `Code: ${res.error.code}\n` +
        `Message: ${res.error.data?.message ?? res.error.message}\n` +
        `Debug: ${res.error.data?.debug ?? 'none'}`,
    );
  }

  console.log(`Odoo RPC ok: ${model}.${method}`, {
    resultType: Array.isArray(res.result) ? 'array' : typeof res.result,
    resultLength: Array.isArray(res.result) ? res.result.length : undefined,
  });

  return res.result;
};

for (const item of items) {
  const j = item.json;

  if (j.skipped || j.empty || j.mappedEmpty) {
    results.push({ json: { ...j, odooSkipped: true, reason: 'no_data' } });
    continue;
  }

  if (!j.odooVals?.ref) {
    results.push({ json: { ...j, error: 'Missing odooVals.ref' } });
    continue;
  }

  const { hellocashId, hellocashNumber, invoiceNumber, ref, odooVals, paymentMethod, taxRate } = j;

  console.log(`Processing item ${ref}`, { hellocashId, ref });

  try {
    const existing = await rpc(
      'account.move',
      'search_read',
      [[['ref', '=', ref]]],
      { fields: ['id', 'state', 'name'], limit: 1 },
    );
    if (Array.isArray(existing) && existing.length > 0) {
      console.log(`Skipping duplicate: ${ref}`, { odooMoveId: existing[0].id });
      results.push({
        json: {
          hellocashId,
          hellocashNumber,
          invoiceNumber,
          ref,
          odooMoveId: existing[0].id,
          odooState: existing[0].state,
          success: true,
          idempotent: true,
          message: `Already exists as ${existing[0].name || ref}`,
        },
      });
      continue;
    }
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    console.warn(`Odoo Post Moves: idempotency check failed for ${ref}: ${msg}`);
  }

  let lastErr;
  let created = false;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const result = await rpc('account.move', 'create', [[odooVals]]);
      const moveId = Array.isArray(result) ? result[0] : result;
      console.log(`Created Odoo move for ${ref}`, { odooMoveId: moveId });
      results.push({
        json: {
          hellocashId,
          hellocashNumber,
          invoiceNumber,
          ref,
          odooMoveId: moveId,
          paymentMethod,
          taxRate,
          success: true,
          attempt,
        },
      });
      created = true;
      break;
    } catch (e) {
      lastErr = e;
      if (attempt < maxAttempts) {
        await new Promise((r) => setTimeout(r, intervalMs));
      }
    }
  }

  if (!created) {
    throw new Error(
      `Failed to create move ${ref} after ${maxAttempts} attempts: ${lastErr instanceof Error ? lastErr.message : String(lastErr)}`,
    );
  }
}

return results;
